# Dependency injection pour les tests
function Get-Utilisateurs {
    param(
        [scriptblock]$GetUsers = { Get-ADUser -Filter * }
    )
    & $GetUsers
}

# Dans les tests :
Get-Utilisateurs -GetUsers { @([PSCustomObject]@{Name='Alice'}) }
